#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,a[N];
priority_queue<int,vector<int>,greater<int>> len[N];
map<int,int> id;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    sort(a+1,a+n+1);
    for(int i=1,cnt=0;i<=n;i++){
        if(i==1 || a[i]!=a[i-1])
            id[a[i]]=++cnt;
    }
    for(int i=1;i<=n;i++){
        if(len[id[a[i]-1]].empty())
            len[id[a[i]]].push(1);
        else{
            int t=len[id[a[i]-1]].top();
            len[id[a[i]-1]].pop(),len[id[a[i]]].push(t+1);
        }
    }
    int ans=1e9;
    for(int i=1;i<=n;i++)
        if(!len[i].empty())
            ans=min(ans,len[i].top());
    printf("%d",ans);
    return 0;
}
